export const animationHtml = `<!--
  使用默认方向键触发边界时，会为当前节点添加回弹动画
-->
<div id="content">
  <div class="list scoped" data-scoped="1">
    <div class="list-item incontroll">落焦点-item-1</div>
    <div class="list-item incontroll">落焦点-item-2</div>
    <div class="list-item incontroll">落焦点-item-3</div>
  </div>
</div>

<style>
  @keyframes bounce-vertical{
    0%, 100%{
      transition-timing-function: cubic-bezier(0.215,.61,.355,1); /*贝塞尔曲线 ： X1 Y1 X2 Y2*/
      transform: translateY(0); /*设置只在Z轴上移动*/
    }
    15%, 40%, 75%{
      transition-timing-function: cubic-bezier(0.215,.61,.355,1); /*贝塞尔曲线 ： X1 Y1 X2 Y2*/
      transform: translateY(-3px);
    }
    30%, 60%, 90%{
      transition-timing-function: cubic-bezier(0.215,.61,.355,1); /*贝塞尔曲线 ： X1 Y1 X2 Y2*/
      transform: translateY(3px);
    }
  }
      
  @keyframes bounce-horizon{
    0%{
      transition-timing-function: cubic-bezier(0.215,.61,.355,1); /*贝塞尔曲线 ： X1 Y1 X2 Y2*/
      transform: translateX(0); /*设置只在Z轴上移动*/
    }
    15%, 40%, 75%{
      transition-timing-function: cubic-bezier(0.215,.61,.355,1); /*贝塞尔曲线 ： X1 Y1 X2 Y2*/
      transform: translateX(-3px);
    }
    30%, 60%, 90%{
      transition-timing-function: cubic-bezier(0.215,.61,.355,1); /*贝塞尔曲线 ： X1 Y1 X2 Y2*/
      transform: translateX(3px);
    }
  }
  
  .anti-shake { // 防抖补丁 解决内部抖动
    &::before {
      content: '.';
      position: absolute;
      color: transparent;
      font-size: 1rem;
      line-height: 1rem;
    }
  }
  
  .bounce-verticalcls{
      animation: bounce-vertical 700ms;
  }
  .bounce-horizoncls{
      animation: bounce-horizon 700ms;
  }
</style>
`;

export const animationJs = `import { LayerScoper } from 'layer-scoper';

const layerScoperCase = new LayerScoper();
...
mounted() {
  layerScoperCase.initController({
    id: 'content',
    className: 'incontroll',
    defaultPoint: { y: 1, x: 1 },
    openAnimate: true, // 开启边界回弹动效
    callBackFn: {
      cbFocusLeft: this.onFocusLeftCallback,
      cbFocusRight: this.onFocusRightCallback,
      cbFocusUp: this.onFocusUpCallback,
      cbFocusDown: this.onFocusDownCallback,
    }
  });
}
...
method: {
  onFocusLeftCallback(cbData) {
    // cbData.isBoundary 为 true 时表示触碰边界
    console.log('焦点左移', cbData.isBoundary);
  },
  onFocusRightCallback(cbData) {
    console.log('焦点右移', cbData.isBoundary);
  },
  onFocusUpCallback(cbData) {
    console.log('焦点上移', cbData.isBoundary);
  },
  onFocusDownCallback(cbData) {
    console.log('焦点下移', cbData.isBoundary);
  },
}
...

...
/**
 * 增加默认纵向回弹动效
 * @param el
 */
export const bounceVerticalAnimate = el => addAnimate({ el, animateClass: 'bounce-verticalcls' });
/**
 * 增加默认横向回弹动效
 * @param el
 */
export const bounceHorizonAnimate = el => addAnimate({ el, animateClass: 'bounce-horizoncls' });
...
`;
